import{_ as a,o as t,c as i,a2 as n}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Sovereign Wallet platform plugin","description":"","frontmatter":{"rfc":49,"title":"Sovereign Wallet platform plugin","status":"Draft","date":"July 2026","author":"kasunben","scope":"plugins/wallet, packages/sdk, runtime, docs; depends on RFC 0060 and RFC 0044","incorporated_into_plan":"Yes - epic tasks 21.1-21.4"},"headers":[],"relativePath":"rfcs/0061-sovereign-wallet.md","filePath":"rfcs/0061-sovereign-wallet.md"}'),s={name:"rfcs/0061-sovereign-wallet.md"};function o(r,e,l,d,p,c){return t(),i("div",null,[...e[0]||(e[0]=[n(`<h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Add Sovereign Wallet as a first-party platform plugin for storing QR/barcode loyalty cards and encrypted snapshots of sensitive personal documents such as IDs and passports.</p><p>Wallet is intentionally conservative in phase 1. It is not a payment wallet, credential issuer, passkey store, or government-ID verification system. It is a private personal vault for cards and document images, built on Sovereign&#39;s core client-side encryption capability.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Users often need a simple place to keep loyalty cards and reference images of important documents. These are useful on mobile and desktop, but document images are highly sensitive. Storing them as plaintext files or Base64 blobs in the DB would contradict Sovereign&#39;s privacy posture.</p><p>Wallet provides a concrete product use case for RFC 0060. It should prove that Sovereign can support operator-unreadable plugin data through a reusable core surface rather than plugin-specific crypto.</p><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li>RFC 0060 defines the core client-side encryption model this plugin depends on.</li><li>RFC 0044 defines plugin file storage and backend-neutral binary object storage.</li><li>RFC 0052 defines plugin portability hooks for export/import/delete.</li><li>Mobile app planning exists in RFC 0058, but Wallet must work in the web/PWA runtime first.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="data-classes" tabindex="-1">Data classes <a class="header-anchor" href="#data-classes" aria-label="Permalink to &quot;Data classes&quot;">​</a></h3><p>Wallet supports two item classes in phase 1:</p><table tabindex="0"><thead><tr><th>Class</th><th>Examples</th><th>Storage default</th></tr></thead><tbody><tr><td>Loyalty card</td><td>QR code, barcode, membership ID</td><td>private record; encryption recommended</td></tr><tr><td>Sensitive document</td><td>passport photo, ID photo, permit</td><td>client-side encrypted object required</td></tr></tbody></table><p>The plugin should bias toward encryption for all user-created wallet items, but sensitive document snapshots must always use client-side encryption.</p><h3 id="loyalty-cards" tabindex="-1">Loyalty cards <a class="header-anchor" href="#loyalty-cards" aria-label="Permalink to &quot;Loyalty cards&quot;">​</a></h3><p>Wallet stores:</p><ul><li>display name;</li><li>card issuer;</li><li>QR/barcode payload;</li><li>barcode type where known;</li><li>optional front/back card image;</li><li>notes.</li></ul><p>The card screen renders the QR/barcode locally in the browser. If the payload is encrypted, the user must unlock Wallet before rendering.</p><h3 id="sensitive-document-snapshots" tabindex="-1">Sensitive document snapshots <a class="header-anchor" href="#sensitive-document-snapshots" aria-label="Permalink to &quot;Sensitive document snapshots&quot;">​</a></h3><p>Document images are encrypted in the browser before upload:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser selects image</span></span>
<span class="line"><span>  -&gt; optional client-side normalization/compression</span></span>
<span class="line"><span>  -&gt; encrypt binary bytes with per-object DEK</span></span>
<span class="line"><span>  -&gt; upload ciphertext through sdk.storage</span></span>
<span class="line"><span>  -&gt; store encrypted metadata and wrapped DEK references</span></span></code></pre></div><p>The server stores no plaintext image, no plaintext original filename, and no plaintext human-readable document metadata unless the user explicitly chooses a non-sensitive hint.</p><p>Display flow:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User opens Wallet</span></span>
<span class="line"><span>  -&gt; Wallet sees encrypted item</span></span>
<span class="line"><span>  -&gt; user unlocks client-side encryption profile</span></span>
<span class="line"><span>  -&gt; plugin downloads ciphertext</span></span>
<span class="line"><span>  -&gt; browser decrypts bytes</span></span>
<span class="line"><span>  -&gt; browser renders Blob URL in &lt;img&gt;</span></span></code></pre></div><p>No decrypted image is sent back to the runtime.</p><h3 id="metadata-minimization" tabindex="-1">Metadata minimization <a class="header-anchor" href="#metadata-minimization" aria-label="Permalink to &quot;Metadata minimization&quot;">​</a></h3><p>Plaintext metadata should be minimal:</p><ul><li>item ID;</li><li>owner user ID;</li><li>created/updated timestamps;</li><li>storage object key;</li><li>encryption version;</li><li>optional coarse <code>kind_hint</code> such as <code>card</code> or <code>document</code>.</li></ul><p>Encrypted metadata includes:</p><ul><li>title;</li><li>issuer;</li><li>document type;</li><li>country;</li><li>document/card number;</li><li>original filename;</li><li>notes;</li><li>thumbnail metadata.</li></ul><h3 id="recovery-ux" tabindex="-1">Recovery UX <a class="header-anchor" href="#recovery-ux" aria-label="Permalink to &quot;Recovery UX&quot;">​</a></h3><p>Wallet must explain that encrypted documents cannot be recovered after password reset unless the user has a recovery secret or another enrolled device. Wallet should not allow sensitive-document upload until client-side encryption setup is complete.</p><h3 id="export-import-and-deletion" tabindex="-1">Export, import, and deletion <a class="header-anchor" href="#export-import-and-deletion" aria-label="Permalink to &quot;Export, import, and deletion&quot;">​</a></h3><p>Wallet participates in RFC 0052 portability hooks:</p><ul><li>export includes encrypted metadata, wrapped keys, and ciphertext objects;</li><li>import preserves ciphertext and remaps storage object IDs;</li><li>delete removes plugin rows, encrypted metadata, wrapped keys, and storage objects;</li><li>export never includes decrypted document bytes unless a future explicit plaintext export option is designed.</li></ul><h2 id="non-goals" tabindex="-1">Non-goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-goals&quot;">​</a></h2><ul><li>payment cards or payment processing;</li><li>Apple Wallet / Google Wallet pass generation;</li><li>government ID verification;</li><li>OCR/search of document contents;</li><li>server-side thumbnails for encrypted documents;</li><li>sharing encrypted wallet items with other users;</li><li>operator escrow of recovery material.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><h3 id="store-images-as-encrypted-base64-in-the-database" tabindex="-1">Store images as encrypted Base64 in the database <a class="header-anchor" href="#store-images-as-encrypted-base64-in-the-database" aria-label="Permalink to &quot;Store images as encrypted Base64 in the database&quot;">​</a></h3><p>Rejected. It wastes space and makes DB backup/migration heavier. Encrypted binary objects belong in plugin storage; DB rows hold metadata and references.</p><h3 id="implement-wallet-crypto-inside-the-plugin" tabindex="-1">Implement Wallet crypto inside the plugin <a class="header-anchor" href="#implement-wallet-crypto-inside-the-plugin" aria-label="Permalink to &quot;Implement Wallet crypto inside the plugin&quot;">​</a></h3><p>Rejected. Wallet should consume the core client-side encryption surface. One-off crypto would be hard to audit and would not help future sensitive plugins.</p><h3 id="server-side-encryption-only" tabindex="-1">Server-side encryption only <a class="header-anchor" href="#server-side-encryption-only" aria-label="Permalink to &quot;Server-side encryption only&quot;">​</a></h3><p>Rejected for sensitive documents. Server-side encryption protects disk/backups but not a compromised operator or runtime.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Whether loyalty cards are encrypted by default or only when the user enables Wallet lock.</li><li>QR/barcode rendering library and supported formats.</li><li>Whether client-side image compression is in phase 1.</li><li>Whether a mobile-optimized scan/import flow waits for the native mobile app.</li><li>Whether Wallet should support a plaintext emergency export mode, and how to warn users if it does.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Build RFC 0060 core client-side encryption.</li><li>Scaffold <code>plugins/wallet</code> as a first-party platform plugin.</li><li>Add loyalty card CRUD and QR/barcode rendering.</li><li>Add encrypted document snapshot storage and display.</li><li>Add export/import/delete hooks.</li><li>Add mobile/PWA ergonomics and later native-mobile capture integration.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>July 2026</td><td>Initial draft</td></tr></tbody></table>`,49)])])}const m=a(s,[["render",o]]);export{u as __pageData,m as default};
